package com.example.gestion_mobilek

import android.content.Context
import android.database.sqlite.SQLiteDatabase
import android.database.sqlite.SQLiteOpenHelper
import java.io.FileOutputStream
import java.io.IOException

class DatabaseHelper(private val context: Context) :
    SQLiteOpenHelper(context, DB_NAME, null, DB_VERSION) {

    companion object {
        private const val DB_NAME = "bdd.db"
        private const val DB_VERSION = 1
        private var dbInstance: SQLiteDatabase? = null  // Instance unique
        private var copied = false  // Flag copie par session
    }

    override fun onCreate(db: SQLiteDatabase?) {}
    override fun onUpgrade(db: SQLiteDatabase?, oldVersion: Int, newVersion: Int) {}

    fun getDatabase(): SQLiteDatabase {
        if (dbInstance == null || !dbInstance!!.isOpen) {
            if (!copied && !context.getDatabasePath(DB_NAME).exists()) {
                copyDatabaseFromAssets()
                copied = true
            }
            val dbPath = context.getDatabasePath(DB_NAME).path
            dbInstance = SQLiteDatabase.openDatabase(
                dbPath, null, SQLiteDatabase.OPEN_READWRITE
            )
        }
        return dbInstance!!
    }

    private fun copyDatabaseFromAssets() {
        val dbFile = context.getDatabasePath(DB_NAME)
        if (!dbFile.parentFile!!.exists()) dbFile.parentFile!!.mkdirs()

        if (dbFile.exists()) return

        try {
            context.assets.open(DB_NAME).use { input ->
                FileOutputStream(dbFile).use { output ->
                    val buffer = ByteArray(1024)
                    var length: Int
                    while (input.read(buffer).also { length = it } > 0) {
                        output.write(buffer, 0, length)
                    }
                    output.flush()
                }
            }
        } catch (e: IOException) {
            e.printStackTrace()
        }
    }
}

package com.example.gestion_mobilek

import android.content.Context
import android.database.sqlite.SQLiteDatabase
import android.database.sqlite.SQLiteOpenHelper
import java.io.FileOutputStream
import java.io.IOException

class DatabaseHelper(private val context: Context) :
    SQLiteOpenHelper(context, LOCAL_DB_NAME, null, DB_VERSION) {

    companion object {
        private const val LOCAL_DB_NAME = "bdd.db"
        const val EXTERNAL_CACHE_DB_NAME = "bdd_online.db"
        private const val DB_VERSION = 1
        private var dbInstance: SQLiteDatabase? = null
        private var currentDbName: String? = null

        @Synchronized
        fun closeActiveDatabase() {
            dbInstance?.takeIf { it.isOpen }?.close()
            dbInstance = null
            currentDbName = null
        }
    }

    override fun onCreate(db: SQLiteDatabase?) {}
    override fun onUpgrade(db: SQLiteDatabase?, oldVersion: Int, newVersion: Int) {}

    fun getDatabase(): SQLiteDatabase {
        return getDatabaseForMode(SettingsStore.isExternalDataSourceEnabled(context))
    }

    @Synchronized
    fun getDatabaseForMode(useExternal: Boolean): SQLiteDatabase {
        val targetName = if (useExternal) EXTERNAL_CACHE_DB_NAME else LOCAL_DB_NAME
        ensureDatabaseExists(targetName)

        if (dbInstance == null || !dbInstance!!.isOpen || currentDbName != targetName) {
            closeActiveDatabase()
            val dbPath = context.getDatabasePath(targetName).path
            dbInstance = SQLiteDatabase.openDatabase(dbPath, null, SQLiteDatabase.OPEN_READWRITE)
            currentDbName = targetName
        }

        return dbInstance!!
    }

    private fun ensureDatabaseExists(dbName: String) {
        val dbFile = context.getDatabasePath(dbName)
        if (!dbFile.exists()) {
            copyDatabaseFromAssets(dbName)
        }
    }

    private fun copyDatabaseFromAssets(targetDbName: String) {
        val dbFile = context.getDatabasePath(targetDbName)
        if (!dbFile.parentFile!!.exists()) dbFile.parentFile!!.mkdirs()

        if (dbFile.exists()) return

        try {
            context.assets.open(LOCAL_DB_NAME).use { input ->
                FileOutputStream(dbFile).use { output ->
                    val buffer = ByteArray(1024)
                    var length: Int
                    while (input.read(buffer).also { length = it } > 0) {
                        output.write(buffer, 0, length)
                    }
                    output.flush()
                }
            }
        } catch (e: IOException) {
            e.printStackTrace()
        }
    }
}

package com.example.gestion_mobilek

import android.content.ContentValues
import android.content.Context
import android.database.Cursor
import android.database.sqlite.SQLiteDatabase
import java.net.Inet4Address
import java.net.InetAddress
import java.text.Normalizer
import java.sql.Connection
import java.sql.DriverManager
import java.sql.SQLException

object ExternalMariaDbSync {

    data class ColumnMapping(
        val localColumn: String,
        val remoteColumn: String
    )

    data class TableDiagnostic(
        val localTable: String,
        val remoteTable: String?,
        val localColumns: List<String>,
        val remoteColumns: List<String>,
        val mappedColumns: List<ColumnMapping>,
        val ignoredLocalColumns: List<String>,
        val ignoredRemoteColumns: List<String>
    )

    data class OnlineDiagnosticReport(
        val host: String,
        val port: Int,
        val configuredDatabase: String?,
        val resolvedDatabase: String,
        val tables: List<TableDiagnostic>,
        val notes: List<String>
    )

    private data class MariaDbConfig(
        val host: String,
        val port: Int,
        val user: String,
        val password: String,
        val forcedDatabase: String?
    )

    private val syncTables = listOf(
        "personnes",
        "gouts",
        "ingrédient",
        "plats",
        "repas",
        "future_repas",
        "future_repas_rappels"
    )
    private val coreTables = setOf("personnes", "gouts", "plats")

    private fun escapeIdent(name: String): String = "`" + name.replace("`", "``") + "`"

    private fun isLikelyIpAddress(host: String): Boolean {
        return host.matches(Regex("^\\d+\\.\\d+\\.\\d+\\.\\d+$")) || host.contains(":")
    }

    private fun connectionHosts(host: String): List<String> {
        if (isLikelyIpAddress(host)) return listOf(host)
        val resolvedV4 = runCatching {
            InetAddress.getAllByName(host)
                .filterIsInstance<Inet4Address>()
                .mapNotNull { it.hostAddress }
        }.getOrDefault(emptyList())

        return listOf(host) + resolvedV4
    }

    private fun jdbcUrl(host: String, port: Int, database: String?): String {
        val dbSegment = database?.let { "/${escapeDbPath(it)}" } ?: "/"
        return "jdbc:mariadb://$host:$port$dbSegment?connectTimeout=5000&socketTimeout=10000&sslMode=disable"
    }

    private fun openConnectionWithFallback(config: MariaDbConfig, database: String?): Connection {
        Class.forName("org.mariadb.jdbc.Driver")
        var lastError: SQLException? = null

        connectionHosts(config.host).distinct().forEach { hostCandidate ->
            try {
                return DriverManager.getConnection(
                    jdbcUrl(hostCandidate, config.port, database),
                    config.user,
                    config.password
                )
            } catch (e: SQLException) {
                lastError = e
            }
        }

        throw SQLException(
            "Connexion socket impossible vers ${config.host}:${config.port}. " +
                "Verifiez ouverture du port, acces reseau mobile/Wi-Fi et bind MariaDB.",
            lastError
        )
    }

    private fun resolveConfig(): MariaDbConfig {
        val host = BuildConfig.MARIADB_HOST.trim()
        val port = BuildConfig.MARIADB_PORT
        val user = BuildConfig.MARIADB_USER.trim()
        val password = BuildConfig.MARIADB_PASSWORD
        val forcedDatabase = BuildConfig.MARIADB_DATABASE.trim().ifBlank { null }

        if (host.isBlank() || port <= 0 || user.isBlank() || password.isBlank()) {
            throw SQLException("Configuration MariaDB manquante: ajoutez le fichier .env")
        }

        return MariaDbConfig(
            host = host,
            port = port,
            user = user,
            password = password,
            forcedDatabase = forcedDatabase
        )
    }

    private fun openServerConnection(config: MariaDbConfig): Connection {
        return openConnectionWithFallback(config, database = null)
    }

    private fun openDatabaseConnection(config: MariaDbConfig, databaseName: String): Connection {
        return openConnectionWithFallback(config, database = databaseName)
    }

    private fun escapeDbPath(name: String): String {
        // Path segment escaping is intentionally strict for safety.
        return name.replace("`", "")
    }

    private fun normalizeTableName(name: String): String {
        val nfd = Normalizer.normalize(name, Normalizer.Form.NFD)
        return nfd.replace(Regex("\\p{Mn}+"), "")
    }

    private fun remoteTableNames(connection: Connection, dbName: String): Set<String> {
        val sql = "SELECT table_name FROM information_schema.tables WHERE table_schema = ?"
        connection.prepareStatement(sql).use { ps ->
            ps.setString(1, dbName)
            ps.executeQuery().use { rs ->
                val names = mutableSetOf<String>()
                while (rs.next()) {
                    names.add(rs.getString(1))
                }
                return names
            }
        }
    }

    private fun resolveRemoteTableName(localTable: String, remoteNames: Set<String>): String? {
        if (remoteNames.contains(localTable)) return localTable
        val normalizedLocal = normalizeTableName(localTable)
        return remoteNames.firstOrNull { normalizeTableName(it).equals(normalizedLocal, ignoreCase = true) }
    }

    private fun remoteTableColumns(connection: Connection, dbName: String, tableName: String): Set<String> {
        val sql = "SELECT column_name FROM information_schema.columns WHERE table_schema = ? AND table_name = ?"
        connection.prepareStatement(sql).use { ps ->
            ps.setString(1, dbName)
            ps.setString(2, tableName)
            ps.executeQuery().use { rs ->
                val cols = mutableSetOf<String>()
                while (rs.next()) {
                    cols.add(rs.getString(1))
                }
                return cols
            }
        }
    }

    private fun resolveRemoteColumnName(localColumn: String, remoteColumns: Set<String>): String? {
        if (remoteColumns.contains(localColumn)) return localColumn
        val normalized = normalizeTableName(localColumn)
        return remoteColumns.firstOrNull { normalizeTableName(it).equals(normalized, ignoreCase = true) }
    }

    private fun resolveLocalColumnName(remoteColumn: String, localColumns: List<String>): String? {
        if (localColumns.contains(remoteColumn)) return remoteColumn
        val normalized = normalizeTableName(remoteColumn)
        return localColumns.firstOrNull { normalizeTableName(it).equals(normalized, ignoreCase = true) }
    }

    private fun mapTableDiagnostic(
        sqliteDb: SQLiteDatabase,
        remoteConn: Connection,
        databaseName: String,
        localTable: String,
        remoteTable: String?
    ): TableDiagnostic {
        val localColumns = sqliteTableColumns(sqliteDb, localTable)
        val remoteColumns = if (remoteTable != null) {
            remoteTableColumns(remoteConn, databaseName, remoteTable).toList()
        } else {
            emptyList()
        }

        val mappedColumns = if (remoteTable != null) {
            localColumns.mapNotNull { localColumn ->
                resolveRemoteColumnName(localColumn, remoteColumns.toSet())?.let { remoteColumn ->
                    ColumnMapping(localColumn, remoteColumn)
                }
            }
        } else {
            emptyList()
        }

        val ignoredLocalColumns = localColumns.filter { localColumn ->
            mappedColumns.none { it.localColumn == localColumn }
        }
        val ignoredRemoteColumns = remoteColumns.filter { remoteColumn ->
            mappedColumns.none { it.remoteColumn == remoteColumn }
        }

        return TableDiagnostic(
            localTable = localTable,
            remoteTable = remoteTable,
            localColumns = localColumns,
            remoteColumns = remoteColumns,
            mappedColumns = mappedColumns,
            ignoredLocalColumns = ignoredLocalColumns,
            ignoredRemoteColumns = ignoredRemoteColumns
        )
    }

    fun buildOnlineDiagnostic(context: Context): Result<OnlineDiagnosticReport> {
        return runCatching {
            val config = resolveConfig()
            openServerConnection(config).use { serverConn ->
                val resolvedDatabase = resolveDatabaseName(context, config, serverConn)
                openDatabaseConnection(config, resolvedDatabase).use { dbConn ->
                    val sqliteDb = DatabaseHelper(context).getDatabaseForMode(useExternal = true)
                    FutureRecettesManager.ensureSchema(sqliteDb)

                    val remoteNames = remoteTableNames(dbConn, resolvedDatabase)
                    val notes = mutableListOf<String>()
                    if (config.forcedDatabase != null) {
                        notes.add("Base forcee via .env : ${config.forcedDatabase}")
                    } else {
                        notes.add("Base distante detectee automatiquement : $resolvedDatabase")
                    }

                    val tables = syncTables.map { localTable ->
                        val remoteTable = resolveRemoteTableName(localTable, remoteNames)
                        mapTableDiagnostic(sqliteDb, dbConn, resolvedDatabase, localTable, remoteTable)
                    }

                    if (tables.none { it.remoteTable != null }) {
                        notes.add("Aucune table mappable detectee dans la base distante.")
                    }

                    OnlineDiagnosticReport(
                        host = config.host,
                        port = config.port,
                        configuredDatabase = config.forcedDatabase,
                        resolvedDatabase = resolvedDatabase,
                        tables = tables,
                        notes = notes
                    )
                }
            }
        }
    }

    private fun hasAllTargetTables(connection: Connection, dbName: String): Boolean {
        val names = remoteTableNames(connection, dbName)
        return coreTables.all { core -> resolveRemoteTableName(core, names) != null }
    }

    private fun resolveDatabaseName(context: Context, config: MariaDbConfig, connection: Connection): String {
        if (!config.forcedDatabase.isNullOrBlank()) {
            return config.forcedDatabase
        }

        val preferred = SettingsStore.getExternalDatabaseName(context)
        if (!preferred.isNullOrBlank() && hasAllTargetTables(connection, preferred)) {
            return preferred
        }

        val candidates = mutableListOf<String>()
        connection.createStatement().use { statement ->
            statement.executeQuery("SHOW DATABASES").use { rs ->
                while (rs.next()) {
                    val db = rs.getString(1)
                    if (!db.equals("information_schema", true) &&
                        !db.equals("mysql", true) &&
                        !db.equals("performance_schema", true) &&
                        !db.equals("sys", true)
                    ) {
                        candidates.add(db)
                    }
                }
            }
        }

        return candidates.firstOrNull { hasAllTargetTables(connection, it) }
            ?: throw SQLException("Aucune base distante compatible trouvee")
    }

    private fun sqliteTableColumns(sqliteDb: SQLiteDatabase, table: String): List<String> {
        val cols = mutableListOf<String>()
        sqliteDb.rawQuery("PRAGMA table_info(${escapeIdent(table)})", null).use { c ->
            if (c.moveToFirst()) {
                do {
                    cols.add(c.getString(1))
                } while (c.moveToNext())
            }
        }
        return cols
    }

    private fun resultSetValueToContent(values: ContentValues, column: String, raw: Any?) {
        when (raw) {
            null -> values.putNull(column)
            is Int -> values.put(column, raw)
            is Long -> values.put(column, raw)
            is Short -> values.put(column, raw.toInt())
            is Float -> values.put(column, raw)
            is Double -> values.put(column, raw)
            is ByteArray -> values.put(column, raw)
            is Boolean -> values.put(column, if (raw) 1 else 0)
            else -> values.put(column, raw.toString())
        }
    }

    private fun pullTableFromRemote(
        sqliteDb: SQLiteDatabase,
        remoteConn: Connection,
        databaseName: String,
        localTable: String,
        remoteTable: String
    ): Boolean {
        val columns = sqliteTableColumns(sqliteDb, localTable)
        if (columns.isEmpty()) return false
        val remoteColumns = remoteTableColumns(remoteConn, databaseName, remoteTable)

        val mappedColumns = columns.mapNotNull { localColumn ->
            resolveRemoteColumnName(localColumn, remoteColumns)?.let { remoteColumn ->
                localColumn to remoteColumn
            }
        }
        if (mappedColumns.isEmpty()) return false

        val sqlColumns = mappedColumns.joinToString(", ") { (_, remoteColumn) -> escapeIdent(remoteColumn) }
        val query = "SELECT $sqlColumns FROM ${escapeIdent(databaseName)}.${escapeIdent(remoteTable)}"

        sqliteDb.beginTransaction()
        try {
            sqliteDb.delete(localTable, null, null)

            remoteConn.createStatement().use { st ->
                st.executeQuery(query).use { rs ->
                    while (rs.next()) {
                        val values = ContentValues()
                        mappedColumns.forEachIndexed { index, (localColumn, _) ->
                            resultSetValueToContent(values, localColumn, rs.getObject(index + 1))
                        }
                        sqliteDb.insert(localTable, null, values)
                    }
                }
            }

            sqliteDb.setTransactionSuccessful()
        } finally {
            sqliteDb.endTransaction()
        }
        return true
    }

    private fun bindCursorValue(psIndex: Int, cursor: Cursor, colIndex: Int, ps: java.sql.PreparedStatement) {
        when (cursor.getType(colIndex)) {
            Cursor.FIELD_TYPE_NULL -> ps.setObject(psIndex, null)
            Cursor.FIELD_TYPE_INTEGER -> ps.setLong(psIndex, cursor.getLong(colIndex))
            Cursor.FIELD_TYPE_FLOAT -> ps.setDouble(psIndex, cursor.getDouble(colIndex))
            Cursor.FIELD_TYPE_BLOB -> ps.setBytes(psIndex, cursor.getBlob(colIndex))
            else -> ps.setString(psIndex, cursor.getString(colIndex))
        }
    }

    private fun pushTableToRemote(
        sqliteDb: SQLiteDatabase,
        remoteConn: Connection,
        databaseName: String,
        localTable: String,
        remoteTable: String
    ): Boolean {
        val localColumns = sqliteTableColumns(sqliteDb, localTable)
        if (localColumns.isEmpty()) return false
        val remoteColumns = remoteTableColumns(remoteConn, databaseName, remoteTable)

        val mappedColumns = remoteColumns.mapNotNull { remoteColumn ->
            resolveLocalColumnName(remoteColumn, localColumns)?.let { localColumn ->
                localColumn to remoteColumn
            }
        }
        if (mappedColumns.isEmpty()) return false

        val escapedColumns = mappedColumns.joinToString(", ") { (_, remoteColumn) -> escapeIdent(remoteColumn) }
        val placeholders = mappedColumns.joinToString(", ") { "?" }
        val selectColumns = mappedColumns.joinToString(", ") { (localColumn, _) -> escapeIdent(localColumn) }
        val deleteSql = "DELETE FROM ${escapeIdent(databaseName)}.${escapeIdent(remoteTable)}"
        val insertSql = "INSERT INTO ${escapeIdent(databaseName)}.${escapeIdent(remoteTable)} ($escapedColumns) VALUES ($placeholders)"
        val selectSql = "SELECT $selectColumns FROM ${escapeIdent(localTable)}"

        remoteConn.createStatement().use { it.executeUpdate(deleteSql) }

        sqliteDb.rawQuery(selectSql, null).use { cursor ->
            remoteConn.prepareStatement(insertSql).use { ps ->
                if (cursor.moveToFirst()) {
                    do {
                        mappedColumns.indices.forEach { i ->
                            bindCursorValue(i + 1, cursor, i, ps)
                        }
                        ps.addBatch()
                    } while (cursor.moveToNext())
                }
                ps.executeBatch()
            }
        }
        return true
    }

    fun connectAndPull(context: Context): Result<String> {
        return runCatching {
            val config = resolveConfig()
            openServerConnection(config).use { serverConn ->
                val dbName = resolveDatabaseName(context, config, serverConn)
                openDatabaseConnection(config, dbName).use { dbConn ->
                    val sqliteDb = DatabaseHelper(context).getDatabaseForMode(useExternal = true)
                    FutureRecettesManager.ensureSchema(sqliteDb)
                    val remoteNames = remoteTableNames(dbConn, dbName)
                    var synced = 0
                    syncTables.forEach { localTable ->
                        val remoteTable = resolveRemoteTableName(localTable, remoteNames)
                        if (remoteTable != null) {
                            if (pullTableFromRemote(sqliteDb, dbConn, dbName, localTable, remoteTable)) {
                                synced++
                            }
                        }
                    }
                    if (synced == 0) {
                        throw SQLException("Aucune table utilisable trouvee dans la base distante '$dbName'")
                    }
                }
                SettingsStore.setExternalDatabaseName(context, dbName)
                SettingsStore.setExternalDataSourceEnabled(context, true)
                DatabaseHelper.closeActiveDatabase()
                dbName
            }
        }
    }

    fun pushExternalToRemote(context: Context): Result<String> {
        return runCatching {
            val config = resolveConfig()
            val dbName = SettingsStore.getExternalDatabaseName(context)
                ?: throw SQLException("Nom de base distante introuvable")

            openDatabaseConnection(config, dbName).use { dbConn ->
                dbConn.autoCommit = false
                try {
                    val sqliteDb = DatabaseHelper(context).getDatabaseForMode(useExternal = true)
                    FutureRecettesManager.ensureSchema(sqliteDb)
                    val remoteNames = remoteTableNames(dbConn, dbName)
                    syncTables.forEach { localTable ->
                        val remoteTable = resolveRemoteTableName(localTable, remoteNames)
                        if (remoteTable != null) {
                            pushTableToRemote(sqliteDb, dbConn, dbName, localTable, remoteTable)
                        }
                    }
                    dbConn.commit()
                } catch (e: Exception) {
                    dbConn.rollback()
                    throw e
                } finally {
                    dbConn.autoCommit = true
                }
            }
            dbName
        }
    }
}

package com.example.gestion_mobilek

import android.content.Intent
import android.database.sqlite.SQLiteException
import android.os.Build
import android.os.Bundle
import android.view.ViewGroup
import android.widget.*
import androidx.appcompat.app.AppCompatActivity
import androidx.appcompat.app.AppCompatDelegate
import com.example.gestion_mobilek.databinding.ActivityMainBinding
import com.google.android.material.bottomsheet.BottomSheetBehavior

class MainActivity : AppCompatActivity() {

    private lateinit var binding: ActivityMainBinding
    private lateinit var dbHelper: DatabaseHelper
    private lateinit var bottomSheetBehavior: BottomSheetBehavior<LinearLayout>

    override fun onCreate(savedInstanceState: Bundle?) {
        AppCompatDelegate.setDefaultNightMode(AppCompatDelegate.MODE_NIGHT_NO)
        super.onCreate(savedInstanceState)
        binding = ActivityMainBinding.inflate(layoutInflater)
        setContentView(binding.root)

        if (Build.VERSION.SDK_INT >= 33 && checkSelfPermission(android.Manifest.permission.POST_NOTIFICATIONS) != android.content.pm.PackageManager.PERMISSION_GRANTED) {
            requestPermissions(arrayOf(android.Manifest.permission.POST_NOTIFICATIONS), 4201)
        }

        dbHelper = DatabaseHelper(this)

        setupBottomSheet()

        binding.btnPlats.setOnClickListener {
            startActivity(Intent(this, ItemListActivity::class.java).apply {
                putExtra("TYPE", "plat")
            })
        }
        binding.btnPersonnes.setOnClickListener {
            startActivity(Intent(this, PersonListActivity::class.java))
        }
        binding.btnIngredients.setOnClickListener {
            startActivity(Intent(this, ItemListActivity::class.java).apply {
                putExtra("TYPE", "ingredient")
            })
        }
        binding.btnFutureRecettes.setOnClickListener {
            startActivity(Intent(this, FutureRecettesActivity::class.java))
        }
        binding.btnHistorique.setOnClickListener {
            startActivity(Intent(this, HistoriqueActivity::class.java))
        }
        binding.btnMenu.setOnClickListener {
            PopupMenu(this, binding.btnMenu).apply {
                this@MainActivity.menuInflater.inflate(R.menu.main_activity_menu, menu)
                setOnMenuItemClickListener { item ->
                    when (item.itemId) {
                        R.id.action_settings -> {
                            startActivity(Intent(this@MainActivity, SettingsActivity::class.java))
                            true
                        }
                        R.id.action_license -> {
                            startActivity(Intent(this@MainActivity, SettingsActivity::class.java).apply {
                                putExtra("OPEN_LICENSE", true)
                            })
                            true
                        }
                        R.id.action_about -> {
                            startActivity(Intent(this@MainActivity, SettingsActivity::class.java).apply {
                                putExtra("OPEN_ABOUT", true)
                            })
                            true
                        }
                        else -> false
                    }
                }
                show()
            }
        }
    }

    override fun onResume() {
        super.onResume()
        try {
            FutureRecettesManager.migrateDueFutureRepas(this, dbHelper.getDatabase())
            FutureReminderScheduler.rescheduleAll(this)
        } catch (_: SQLiteException) {
        }
        binding.containerLastMeals.post {
            loadLastMeals()
        }
    }

    // ─── BOTTOM SHEET ───────────────────────────────────────────────

    private fun setupBottomSheet() {
        bottomSheetBehavior = BottomSheetBehavior.from(binding.bottomSheet)
        bottomSheetBehavior.peekHeight = dpToPx(80)
        bottomSheetBehavior.state = BottomSheetBehavior.STATE_COLLAPSED
        bottomSheetBehavior.isHideable = false

        val screenHeight = resources.displayMetrics.heightPixels
        val maxHeight = screenHeight / 2

        binding.bottomSheet.post {
            val params = binding.bottomSheet.layoutParams
            params.height = maxHeight
            binding.bottomSheet.layoutParams = params
        }
    }

    private fun dpToPx(dp: Int): Int =
        (dp * resources.displayMetrics.density).toInt()

    private fun updateStatsFromDB() {
        try {
            dbHelper.getDatabase()
        } catch (_: SQLiteException) { /* silencieux */ }
    }

    // ─── 3 DERNIERS REPAS ───────────────────────────────────────────

    private fun loadLastMeals() {
        binding.containerLastMeals.removeAllViews()
        try {
            val db = dbHelper.getDatabase()
            val dateConfig = RepasDateCompat.resolve(db)
            val cursor = if (dateConfig.isStorageDate) {
                val todayStorage = DateStorageUtils.todayStorageDate()
                val todaySortable = DateStorageUtils.toSortable(todayStorage) ?: "20260416"
                val orderExpr = "SUBSTR(${dateConfig.columnName}, 5) || SUBSTR(${dateConfig.columnName}, 3, 2) || SUBSTR(${dateConfig.columnName}, 1, 2)"
                db.rawQuery(
                    """SELECT id, nom_plat, id_personnes, ${dateConfig.columnName}
                       FROM repas
                       WHERE ${dateConfig.columnName} IS NOT NULL AND TRIM(${dateConfig.columnName}) != ''
                         AND $orderExpr < ?
                       ORDER BY $orderExpr DESC
                       LIMIT 3""",
                    arrayOf(todaySortable)
                )
            } else {
                db.rawQuery(
                    """SELECT id, nom_plat, id_personnes, ${dateConfig.columnName}
                       FROM repas
                       WHERE ${dateConfig.columnName} > 0
                       ORDER BY ${dateConfig.columnName} ASC
                       LIMIT 3""",
                    null
                )
            }
            if (cursor.moveToFirst()) {
                do {
                    addLastMealRow(
                        cursor.getInt(0),
                        cursor.getString(1) ?: "",
                        cursor.getString(2) ?: "",
                        RepasDateCompat.cursorDateAsStorage(dateConfig, cursor.getString(3))
                    )
                } while (cursor.moveToNext())
            } else {
                val tv = TextView(this)
                tv.text = "Aucun repas passé"
                tv.textSize = 14f
                tv.setTextColor(0xFFAAAAAA.toInt())
                tv.setPadding(0, 8, 0, 8)
                binding.containerLastMeals.addView(tv)
            }
            cursor.close()
        } catch (e: SQLiteException) { /* silencieux */ }
    }

    private fun addLastMealRow(
        repasId: Int,
        nomPlat: String,
        idPersonnes: String,
        dateDernierRepas: String?
    ) {
        val dateStr = DateStorageUtils.displayFromStorage(dateDernierRepas)

        // Plats CSV : max 2 affichés
        val platsList = nomPlat.split(",").filter { it.isNotBlank() }
        val platsText = when {
            platsList.isEmpty() -> "Aucun plat"
            platsList.size <= 2 -> platsList.joinToString(", ")
            else -> "${platsList[0]}, ${platsList[1]}..."
        }

        // Personnes : max 2 affichées
        val nomsPersonnes = getPersonNames(idPersonnes)
        val noms = nomsPersonnes.split(", ").filter { it.isNotBlank() }
        val personnesText = when {
            noms.isEmpty() -> "Aucune personne"
            noms.size <= 2 -> noms.joinToString(", ")
            else -> "${noms[0]}, ${noms[1]} +${noms.size - 2}"
        }

        val btn = Button(this)
        btn.layoutParams = LinearLayout.LayoutParams(
            ViewGroup.LayoutParams.MATCH_PARENT,
            ViewGroup.LayoutParams.WRAP_CONTENT
        ).apply { topMargin = 4; bottomMargin = 4 }
        btn.textSize = 13f
        btn.textAlignment = android.view.View.TEXT_ALIGNMENT_TEXT_START
        btn.text = "️ $platsText\n $personnesText\n $dateStr"
        btn.setTextColor(0xFFFFFFFF.toInt())
        btn.setBackgroundColor(0xFF2A2A2A.toInt())
        btn.setOnClickListener {
            startActivity(Intent(this, HistoriqueActivity::class.java))
        }
        binding.containerLastMeals.addView(btn)
    }


    private fun getPersonNames(idPersonnes: String): String {
        if (idPersonnes.isBlank()) return ""
        return try {
            val db = dbHelper.getDatabase()
            val ids = idPersonnes.split(",").filter { it.isNotBlank() }
            val noms = mutableListOf<String>()
            ids.forEach { id ->
                val c = db.rawQuery(
                    "SELECT nom FROM personnes WHERE id = ?",
                    arrayOf(id.trim())
                )
                if (c.moveToFirst()) noms.add(c.getString(0))
                c.close()
            }
            noms.joinToString(", ")
        } catch (e: SQLiteException) { "?" }
    }
}

package com.example.gestion_mobilek

import android.content.Intent
import android.database.sqlite.SQLiteException
import android.os.Build
import android.os.Bundle
import android.view.ViewGroup
import android.widget.*
import androidx.appcompat.app.AppCompatActivity
import androidx.appcompat.app.AppCompatDelegate
import com.example.gestion_mobilek.databinding.ActivityMainBinding
import com.google.android.material.bottomsheet.BottomSheetBehavior

class MainActivity : AppCompatActivity() {

    private lateinit var binding: ActivityMainBinding
    private lateinit var dbHelper: DatabaseHelper
    private lateinit var bottomSheetBehavior: BottomSheetBehavior<LinearLayout>
    @Volatile
    private var connectionBusy = false

    override fun onCreate(savedInstanceState: Bundle?) {
        AppCompatDelegate.setDefaultNightMode(AppCompatDelegate.MODE_NIGHT_NO)
        super.onCreate(savedInstanceState)
        binding = ActivityMainBinding.inflate(layoutInflater)
        setContentView(binding.root)

        if (Build.VERSION.SDK_INT >= 33 && checkSelfPermission(android.Manifest.permission.POST_NOTIFICATIONS) != android.content.pm.PackageManager.PERMISSION_GRANTED) {
            requestPermissions(arrayOf(android.Manifest.permission.POST_NOTIFICATIONS), 4201)
        }

        dbHelper = DatabaseHelper(this)

        setupBottomSheet()

        binding.btnPlats.setOnClickListener {
            startActivity(Intent(this, ItemListActivity::class.java).apply {
                putExtra("TYPE", "plat")
            })
        }
        binding.btnPersonnes.setOnClickListener {
            startActivity(Intent(this, PersonListActivity::class.java))
        }
        binding.btnIngredients.setOnClickListener {
            startActivity(Intent(this, ItemListActivity::class.java).apply {
                putExtra("TYPE", "ingredient")
            })
        }
        binding.btnFutureRecettes.setOnClickListener {
            startActivity(Intent(this, FutureRecettesActivity::class.java))
        }
        binding.btnHistorique.setOnClickListener {
            startActivity(Intent(this, HistoriqueActivity::class.java))
        }
        binding.btnMenu.setOnClickListener {
            PopupMenu(this, binding.btnMenu).apply {
                this@MainActivity.menuInflater.inflate(R.menu.main_activity_menu, menu)
                setOnMenuItemClickListener { item ->
                    when (item.itemId) {
                        R.id.action_settings -> {
                            startActivity(Intent(this@MainActivity, SettingsActivity::class.java))
                            true
                        }
                        R.id.action_license -> {
                            startActivity(Intent(this@MainActivity, SettingsActivity::class.java).apply {
                                putExtra("OPEN_LICENSE", true)
                            })
                            true
                        }
                        R.id.action_about -> {
                            startActivity(Intent(this@MainActivity, SettingsActivity::class.java).apply {
                                putExtra("OPEN_ABOUT", true)
                            })
                            true
                        }
                        else -> false
                    }
                }
                show()
            }
        }

        binding.btnConnectExternal.setOnClickListener {
            if (connectionBusy) return@setOnClickListener
            if (SettingsStore.isExternalDataSourceEnabled(this)) {
                switchBackToLocal()
            } else {
                connectToExternalSource()
            }
        }

        refreshDataSourceUi()

        if (SettingsStore.shouldKeepExternalMode(this) && !SettingsStore.isExternalDataSourceEnabled(this)) {
            connectToExternalSource(auto = true)
        }
    }

    override fun onResume() {
        super.onResume()
        try {
            FutureRecettesManager.migrateDueFutureRepas(this, dbHelper.getDatabase())
            FutureReminderScheduler.rescheduleAll(this)
        } catch (_: SQLiteException) {
        }
        refreshDataSourceUi()
        if (!connectionBusy && SettingsStore.shouldKeepExternalMode(this) && !SettingsStore.isExternalDataSourceEnabled(this)) {
            connectToExternalSource(auto = true)
        }
        binding.containerLastMeals.post {
            loadLastMeals()
        }
    }

    private fun setConnectionBusy(busy: Boolean) {
        connectionBusy = busy
        setHomeButtonsEnabled(!busy)
        if (busy) {
            binding.btnConnectExternal.text = getString(R.string.home_connecting)
        } else {
            refreshDataSourceUi()
        }
    }

    private fun setHomeButtonsEnabled(enabled: Boolean) {
        val views = listOf(
            binding.btnMenu,
            binding.btnIngredients,
            binding.btnFutureRecettes,
            binding.btnPersonnes,
            binding.btnPlats,
            binding.btnHistorique,
            binding.btnConnectExternal
        )
        views.forEach { view ->
            view.isEnabled = enabled
            view.alpha = if (enabled) 1f else 0.45f
        }
        binding.bottomSheet.isEnabled = enabled
        binding.bottomSheet.isClickable = enabled
    }

    private fun refreshDataSourceUi() {
        val external = SettingsStore.isExternalDataSourceEnabled(this)
        if (external) {
            binding.btnConnectExternal.text = getString(R.string.home_disconnect_external)
            val dbName = SettingsStore.getExternalDatabaseName(this) ?: "?"
            binding.tvDataSourceStatus.text = getString(R.string.home_data_source_external, dbName)
        } else {
            binding.btnConnectExternal.text = getString(R.string.home_connect_external)
            binding.tvDataSourceStatus.text = getString(R.string.home_data_source_local)
        }
    }

    private fun connectToExternalSource(auto: Boolean = false) {
        if (connectionBusy) return
        setConnectionBusy(true)
        Thread {
            val result = ExternalMariaDbSync.connectAndPull(applicationContext)
            runOnUiThread {
                setConnectionBusy(false)
                result
                    .onSuccess { dbName ->
                        if (!auto) {
                            Toast.makeText(this, getString(R.string.home_external_connected, dbName), Toast.LENGTH_LONG).show()
                        }
                        loadLastMeals()
                    }
                    .onFailure { e ->
                        if (!auto) {
                            Toast.makeText(this, getString(R.string.home_external_connection_failed, e.message ?: "?"), Toast.LENGTH_LONG).show()
                        }
                    }
            }
        }.start()
    }

    private fun switchBackToLocal() {
        setConnectionBusy(true)
        Thread {
            val pushResult = ExternalMariaDbSync.pushExternalToRemote(applicationContext)
            SettingsStore.setExternalDataSourceEnabled(applicationContext, false)
            SettingsStore.setKeepExternalMode(applicationContext, false)
            DatabaseHelper.closeActiveDatabase()
            runOnUiThread {
                setConnectionBusy(false)
                pushResult
                    .onSuccess {
                        Toast.makeText(this, getString(R.string.home_returned_local), Toast.LENGTH_SHORT).show()
                    }
                    .onFailure {
                        Toast.makeText(this, getString(R.string.home_returned_local_unsynced), Toast.LENGTH_LONG).show()
                    }
                loadLastMeals()
            }
        }.start()
    }

    // ─── BOTTOM SHEET ───────────────────────────────────────────────

    private fun setupBottomSheet() {
        bottomSheetBehavior = BottomSheetBehavior.from(binding.bottomSheet)
        bottomSheetBehavior.peekHeight = dpToPx(80)
        bottomSheetBehavior.state = BottomSheetBehavior.STATE_COLLAPSED
        bottomSheetBehavior.isHideable = false

        val screenHeight = resources.displayMetrics.heightPixels
        val maxHeight = screenHeight / 2

        binding.bottomSheet.post {
            val params = binding.bottomSheet.layoutParams
            params.height = maxHeight
            binding.bottomSheet.layoutParams = params
        }
    }

    private fun dpToPx(dp: Int): Int =
        (dp * resources.displayMetrics.density).toInt()

    private fun updateStatsFromDB() {
        try {
            dbHelper.getDatabase()
        } catch (_: SQLiteException) { /* silencieux */ }
    }

    // ─── 3 DERNIERS REPAS ───────────────────────────────────────────

    private fun loadLastMeals() {
        binding.containerLastMeals.removeAllViews()
        try {
            val db = dbHelper.getDatabase()
            val dateConfig = RepasDateCompat.resolve(db)
            val cursor = if (dateConfig.isStorageDate) {
                val todayStorage = DateStorageUtils.todayStorageDate()
                val todaySortable = DateStorageUtils.toSortable(todayStorage) ?: "20260416"
                val orderExpr = "SUBSTR(${dateConfig.columnName}, 5) || SUBSTR(${dateConfig.columnName}, 3, 2) || SUBSTR(${dateConfig.columnName}, 1, 2)"
                db.rawQuery(
                    """SELECT id, nom_plat, id_personnes, ${dateConfig.columnName}
                       FROM repas
                       WHERE ${dateConfig.columnName} IS NOT NULL AND TRIM(${dateConfig.columnName}) != ''
                         AND $orderExpr < ?
                       ORDER BY $orderExpr DESC
                       LIMIT 3""",
                    arrayOf(todaySortable)
                )
            } else {
                db.rawQuery(
                    """SELECT id, nom_plat, id_personnes, ${dateConfig.columnName}
                       FROM repas
                       WHERE ${dateConfig.columnName} > 0
                       ORDER BY ${dateConfig.columnName} ASC
                       LIMIT 3""",
                    null
                )
            }
            if (cursor.moveToFirst()) {
                do {
                    addLastMealRow(
                        cursor.getInt(0),
                        cursor.getString(1) ?: "",
                        cursor.getString(2) ?: "",
                        RepasDateCompat.cursorDateAsStorage(dateConfig, cursor.getString(3))
