package com.example.gestion_mobilek

import android.os.Bundle
import android.widget.Button
import android.widget.ImageButton
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class OnlineDiagnosticActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_online_diagnostic)

        findViewById<ImageButton>(R.id.btnBack).setOnClickListener { finish() }

        val tvStatus = findViewById<TextView>(R.id.tvDiagnosticStatus)
        val tvContent = findViewById<TextView>(R.id.tvDiagnosticContent)
        val btnRefresh = findViewById<Button>(R.id.btnRefreshDiagnostic)

        fun refresh() {
            tvStatus.text = getString(R.string.online_diagnostic_loading)
            tvContent.text = ""
            btnRefresh.isEnabled = false

            Thread {
                val result = ExternalMariaDbSync.buildOnlineDiagnostic(applicationContext)
                runOnUiThread {
                    btnRefresh.isEnabled = true
                    result
                        .onSuccess { report ->
                            tvStatus.text = getString(R.string.online_diagnostic_ready)
                            tvContent.text = formatReport(report)
                        }
                        .onFailure { error ->
                            tvStatus.text = getString(R.string.online_diagnostic_error)
                            tvContent.text = errorMessage(error)
                            Toast.makeText(this, error.message ?: getString(R.string.online_diagnostic_error), Toast.LENGTH_LONG).show()
                        }
                }
            }.start()
        }

        btnRefresh.setOnClickListener { refresh() }
        refresh()
    }

    private fun errorMessage(error: Throwable): String {
        return buildString {
            appendLine(getString(R.string.online_diagnostic_error))
            appendLine()
            appendLine(error.message ?: getString(R.string.online_diagnostic_error_unknown))
        }
    }

    private fun formatReport(report: ExternalMariaDbSync.OnlineDiagnosticReport): String {
        return buildString {
            appendLine(getString(R.string.online_diagnostic_host, report.host, report.port))
            appendLine(getString(R.string.online_diagnostic_database, report.resolvedDatabase))
            appendLine(getString(R.string.online_diagnostic_configured_database, report.configuredDatabase ?: getString(R.string.online_diagnostic_none)))
            appendLine()
            report.notes.forEach { note ->
                appendLine("• $note")
            }
            appendLine()
            report.tables.forEach { table ->
                appendLine(getString(R.string.online_diagnostic_table_title, table.localTable, table.remoteTable ?: getString(R.string.online_diagnostic_table_missing)))
                appendLine(getString(R.string.online_diagnostic_columns_local, joinOrNone(table.localColumns)))
                appendLine(getString(R.string.online_diagnostic_columns_remote, joinOrNone(table.remoteColumns)))
                appendLine(getString(R.string.online_diagnostic_columns_mapped, if (table.mappedColumns.isEmpty()) getString(R.string.online_diagnostic_none) else table.mappedColumns.joinToString(", ") { "${it.localColumn} → ${it.remoteColumn}" }))
                appendLine(getString(R.string.online_diagnostic_columns_ignored_local, joinOrNone(table.ignoredLocalColumns)))
                appendLine(getString(R.string.online_diagnostic_columns_ignored_remote, joinOrNone(table.ignoredRemoteColumns)))
                appendLine()
            }
        }.trimEnd()
    }

    private fun joinOrNone(items: List<String>): String {
        return if (items.isEmpty()) getString(R.string.online_diagnostic_none) else items.joinToString(", ")
    }
}

package com.example.gestion_mobilek

import android.app.AlertDialog
import android.app.AlarmManager
import android.content.Intent
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.provider.Settings
import android.widget.Button
import android.widget.CheckBox
import android.widget.ImageButton
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class SettingsActivity : AppCompatActivity() {

    companion object {
        private const val REQUEST_POST_NOTIFICATIONS = 5401
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_settings)

        findViewById<ImageButton>(R.id.btnBack).setOnClickListener { finish() }

        val tvNotificationStatus = findViewById<TextView>(R.id.tvNotificationStatus)
        val tvAlarmStatus = findViewById<TextView>(R.id.tvAlarmStatus)
        val tvAbout = findViewById<TextView>(R.id.tvAbout)
        val cbReminderNotifications = findViewById<CheckBox>(R.id.cbReminderNotifications)

        cbReminderNotifications.isChecked = SettingsStore.areReminderNotificationsEnabled(this)
        cbReminderNotifications.setOnCheckedChangeListener { _, isChecked ->
            SettingsStore.setReminderNotificationsEnabled(this, isChecked)
            refreshStatuses(tvNotificationStatus, tvAlarmStatus)
        }

        findViewById<Button>(R.id.btnRequestNotifications).setOnClickListener {
            requestNotificationPermission()
        }
        findViewById<Button>(R.id.btnOpenAppSettings).setOnClickListener {
            openAppSettings()
        }
        findViewById<Button>(R.id.btnOpenAlarmSettings).setOnClickListener {
            openAlarmSettings()
        }
        findViewById<Button>(R.id.btnResyncReminders).setOnClickListener {
            FutureReminderScheduler.rescheduleAll(this)
            Toast.makeText(this, getString(R.string.settings_reminders_resynced), Toast.LENGTH_SHORT).show()
        }
        findViewById<Button>(R.id.btnLicense).setOnClickListener {
            showLicenseDialog()
        }

        tvAbout.text = getAppVersionSummary()

        refreshStatuses(tvNotificationStatus, tvAlarmStatus)

        when {
            intent.getBooleanExtra("OPEN_LICENSE", false) -> showLicenseDialog()
            intent.getBooleanExtra("OPEN_ABOUT", false) -> showAboutDialog()
        }
    }

    private fun refreshStatuses(tvNotificationStatus: TextView, tvAlarmStatus: TextView) {
        val notificationsGranted = if (Build.VERSION.SDK_INT < 33) {
            true
        } else {
            checkSelfPermission(android.Manifest.permission.POST_NOTIFICATIONS) == android.content.pm.PackageManager.PERMISSION_GRANTED
        }
        tvNotificationStatus.text = getString(
            R.string.settings_notification_status,
            if (notificationsGranted) getString(R.string.settings_status_granted) else getString(R.string.settings_status_missing)
        )

        val alarmManager = getSystemService(ALARM_SERVICE) as AlarmManager
        val exactAlarmAllowed = if (Build.VERSION.SDK_INT < Build.VERSION_CODES.S) {
            true
        } else {
            alarmManager.canScheduleExactAlarms()
        }
        tvAlarmStatus.text = getString(
            R.string.settings_alarm_status,
            if (exactAlarmAllowed) getString(R.string.settings_status_granted) else getString(R.string.settings_status_missing)
        )
    }

    private fun requestNotificationPermission() {
        if (Build.VERSION.SDK_INT < 33) {
            Toast.makeText(this, getString(R.string.settings_notifications_not_required), Toast.LENGTH_SHORT).show()
            return
        }
        if (checkSelfPermission(android.Manifest.permission.POST_NOTIFICATIONS) == android.content.pm.PackageManager.PERMISSION_GRANTED) {
            Toast.makeText(this, getString(R.string.settings_status_granted), Toast.LENGTH_SHORT).show()
            return
        }
        requestPermissions(arrayOf(android.Manifest.permission.POST_NOTIFICATIONS), REQUEST_POST_NOTIFICATIONS)
    }

    private fun openAppSettings() {
        val intent = Intent(Settings.ACTION_APPLICATION_DETAILS_SETTINGS).apply {
            data = Uri.fromParts("package", packageName, null)
        }
        startActivity(intent)
    }

    private fun openAlarmSettings() {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.S) {
            Toast.makeText(this, getString(R.string.settings_alarm_not_required), Toast.LENGTH_SHORT).show()
            return
        }
        startActivity(Intent(Settings.ACTION_REQUEST_SCHEDULE_EXACT_ALARM).apply {
            data = Uri.parse("package:$packageName")
        })
    }

    private fun showLicenseDialog() {
        AlertDialog.Builder(this)
            .setTitle(R.string.settings_license)
            .setMessage(getString(R.string.settings_license_text))
            .setPositiveButton(android.R.string.ok, null)
            .show()
    }

    private fun showAboutDialog() {
        val packageInfo = packageManager.getPackageInfo(packageName, 0)
        val versionName = packageInfo.versionName ?: "?"
        val versionCode = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            packageInfo.longVersionCode
        } else {
            @Suppress("DEPRECATION")
            packageInfo.versionCode.toLong()
        }

        AlertDialog.Builder(this)
            .setTitle(R.string.settings_about_title)
            .setMessage(getString(R.string.settings_about_dialog_text, versionName, versionCode))
            .setPositiveButton(android.R.string.ok, null)
            .show()
    }

    private fun getAppVersionSummary(): String {
        val packageInfo = packageManager.getPackageInfo(packageName, 0)
        val versionName = packageInfo.versionName ?: "?"
        val versionCode = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            packageInfo.longVersionCode
        } else {
            @Suppress("DEPRECATION")
            packageInfo.versionCode.toLong()
        }
        return getString(R.string.settings_about_summary, versionName, versionCode)
    }
}

package com.example.gestion_mobilek

import android.app.AlertDialog
import android.app.AlarmManager
import android.content.Intent
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.provider.Settings
import android.widget.Button
import android.widget.CheckBox
import android.widget.ImageButton
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class SettingsActivity : AppCompatActivity() {

    companion object {
        private const val REQUEST_POST_NOTIFICATIONS = 5401
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_settings)

        findViewById<ImageButton>(R.id.btnBack).setOnClickListener { finish() }

        val tvNotificationStatus = findViewById<TextView>(R.id.tvNotificationStatus)
        val tvAlarmStatus = findViewById<TextView>(R.id.tvAlarmStatus)
        val tvDataSourceStatus = findViewById<TextView>(R.id.tvDataSourceStatus)
        val tvRemoteDbName = findViewById<TextView>(R.id.tvRemoteDbName)
        val tvAbout = findViewById<TextView>(R.id.tvAbout)
        val cbReminderNotifications = findViewById<CheckBox>(R.id.cbReminderNotifications)
        val cbKeepExternalMode = findViewById<CheckBox>(R.id.cbKeepExternalMode)

        cbReminderNotifications.isChecked = SettingsStore.areReminderNotificationsEnabled(this)
        cbReminderNotifications.setOnCheckedChangeListener { _, isChecked ->
            SettingsStore.setReminderNotificationsEnabled(this, isChecked)
            refreshStatuses(tvNotificationStatus, tvAlarmStatus, tvDataSourceStatus, tvRemoteDbName)
        }

        cbKeepExternalMode.isChecked = SettingsStore.shouldKeepExternalMode(this)
        cbKeepExternalMode.setOnCheckedChangeListener { _, isChecked ->
            SettingsStore.setKeepExternalMode(this, isChecked)
            refreshStatuses(tvNotificationStatus, tvAlarmStatus, tvDataSourceStatus, tvRemoteDbName)
        }

        findViewById<Button>(R.id.btnRequestNotifications).setOnClickListener {
            requestNotificationPermission()
        }
        findViewById<Button>(R.id.btnOpenAppSettings).setOnClickListener {
            openAppSettings()
        }
        findViewById<Button>(R.id.btnOpenAlarmSettings).setOnClickListener {
            openAlarmSettings()
        }
        findViewById<Button>(R.id.btnOnlineDiagnostic).setOnClickListener {
            startActivity(Intent(this, OnlineDiagnosticActivity::class.java))
        }
        findViewById<Button>(R.id.btnResyncReminders).setOnClickListener {
            FutureReminderScheduler.rescheduleAll(this)
            Toast.makeText(this, getString(R.string.settings_reminders_resynced), Toast.LENGTH_SHORT).show()
        }
        findViewById<Button>(R.id.btnLicense).setOnClickListener {
            showLicenseDialog()
        }

        tvAbout.text = getAppVersionSummary()

        refreshStatuses(tvNotificationStatus, tvAlarmStatus, tvDataSourceStatus, tvRemoteDbName)

        when {
            intent.getBooleanExtra("OPEN_LICENSE", false) -> showLicenseDialog()
            intent.getBooleanExtra("OPEN_ABOUT", false) -> showAboutDialog()
        }
    }

    private fun refreshStatuses(
        tvNotificationStatus: TextView,
        tvAlarmStatus: TextView,
        tvDataSourceStatus: TextView,
        tvRemoteDbName: TextView
    ) {
        val notificationsGranted = if (Build.VERSION.SDK_INT < 33) {
            true
        } else {
            checkSelfPermission(android.Manifest.permission.POST_NOTIFICATIONS) == android.content.pm.PackageManager.PERMISSION_GRANTED
        }
        tvNotificationStatus.text = getString(
            R.string.settings_notification_status,
            if (notificationsGranted) getString(R.string.settings_status_granted) else getString(R.string.settings_status_missing)
        )

        val alarmManager = getSystemService(ALARM_SERVICE) as AlarmManager
        val exactAlarmAllowed = if (Build.VERSION.SDK_INT < Build.VERSION_CODES.S) {
            true
        } else {
            alarmManager.canScheduleExactAlarms()
        }
        tvAlarmStatus.text = getString(
            R.string.settings_alarm_status,
            if (exactAlarmAllowed) getString(R.string.settings_status_granted) else getString(R.string.settings_status_missing)
        )

        val dataSourceText = if (SettingsStore.isExternalDataSourceEnabled(this)) {
            getString(R.string.settings_data_source_external)
        } else {
            getString(R.string.settings_data_source_local)
        }
        tvDataSourceStatus.text = getString(R.string.settings_data_source_status, dataSourceText)

        val dbName = SettingsStore.getExternalDatabaseName(this)
        tvRemoteDbName.text = getString(
            R.string.settings_remote_database,
            dbName ?: getString(R.string.settings_remote_database_unknown)
        )
    }

    private fun requestNotificationPermission() {
        if (Build.VERSION.SDK_INT < 33) {
            Toast.makeText(this, getString(R.string.settings_notifications_not_required), Toast.LENGTH_SHORT).show()
            return
        }
        if (checkSelfPermission(android.Manifest.permission.POST_NOTIFICATIONS) == android.content.pm.PackageManager.PERMISSION_GRANTED) {
            Toast.makeText(this, getString(R.string.settings_status_granted), Toast.LENGTH_SHORT).show()
            return
        }
        requestPermissions(arrayOf(android.Manifest.permission.POST_NOTIFICATIONS), REQUEST_POST_NOTIFICATIONS)
    }

    private fun openAppSettings() {
        val intent = Intent(Settings.ACTION_APPLICATION_DETAILS_SETTINGS).apply {
            data = Uri.fromParts("package", packageName, null)
        }
        startActivity(intent)
    }

    private fun openAlarmSettings() {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.S) {
            Toast.makeText(this, getString(R.string.settings_alarm_not_required), Toast.LENGTH_SHORT).show()
            return
        }
        startActivity(Intent(Settings.ACTION_REQUEST_SCHEDULE_EXACT_ALARM).apply {
            data = Uri.parse("package:$packageName")
        })
    }

    private fun showLicenseDialog() {
        AlertDialog.Builder(this)
            .setTitle(R.string.settings_license)
            .setMessage(getString(R.string.settings_license_text))
            .setPositiveButton(android.R.string.ok, null)
            .show()
    }

    private fun showAboutDialog() {
        val packageInfo = packageManager.getPackageInfo(packageName, 0)
        val versionName = packageInfo.versionName ?: "?"
        val versionCode = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            packageInfo.longVersionCode
        } else {
            @Suppress("DEPRECATION")
            packageInfo.versionCode.toLong()
        }

        AlertDialog.Builder(this)
            .setTitle(R.string.settings_about_title)
            .setMessage(getString(R.string.settings_about_dialog_text, versionName, versionCode))
            .setPositiveButton(android.R.string.ok, null)
            .show()
    }

    private fun getAppVersionSummary(): String {
        val packageInfo = packageManager.getPackageInfo(packageName, 0)
        val versionName = packageInfo.versionName ?: "?"
        val versionCode = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            packageInfo.longVersionCode
        } else {
            @Suppress("DEPRECATION")
            packageInfo.versionCode.toLong()
        }
        return getString(R.string.settings_about_summary, versionName, versionCode)
    }
}

package com.example.gestion_mobilek

import android.content.Context
import androidx.core.content.edit

object SettingsStore {
    private const val PREFS = "app_settings"
    private const val KEY_REMINDER_NOTIFICATIONS = "reminder_notifications_enabled"

    fun areReminderNotificationsEnabled(context: Context): Boolean {
        return context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .getBoolean(KEY_REMINDER_NOTIFICATIONS, true)
    }

    fun setReminderNotificationsEnabled(context: Context, enabled: Boolean) {
        context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit { putBoolean(KEY_REMINDER_NOTIFICATIONS, enabled) }
    }
}

package com.example.gestion_mobilek

import android.content.Context
import androidx.core.content.edit

object SettingsStore {
    private const val PREFS = "app_settings"
    private const val KEY_REMINDER_NOTIFICATIONS = "reminder_notifications_enabled"
    private const val KEY_EXTERNAL_SOURCE_ENABLED = "external_source_enabled"
    private const val KEY_EXTERNAL_DATABASE_NAME = "external_database_name"
    private const val KEY_KEEP_EXTERNAL_MODE = "keep_external_mode"

    fun areReminderNotificationsEnabled(context: Context): Boolean {
        return context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .getBoolean(KEY_REMINDER_NOTIFICATIONS, true)
    }

    fun setReminderNotificationsEnabled(context: Context, enabled: Boolean) {
        context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit { putBoolean(KEY_REMINDER_NOTIFICATIONS, enabled) }
    }

    fun isExternalDataSourceEnabled(context: Context): Boolean {
        return context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .getBoolean(KEY_EXTERNAL_SOURCE_ENABLED, false)
    }

    fun setExternalDataSourceEnabled(context: Context, enabled: Boolean) {
        context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit { putBoolean(KEY_EXTERNAL_SOURCE_ENABLED, enabled) }
    }

    fun getExternalDatabaseName(context: Context): String? {
        val raw = context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .getString(KEY_EXTERNAL_DATABASE_NAME, null)
        return raw?.takeIf { it.isNotBlank() }
    }

    fun setExternalDatabaseName(context: Context, name: String?) {
        context.getSharedPreferences(PREFS, Context.MODE_PRIVATE).edit {
            if (name.isNullOrBlank()) {
                remove(KEY_EXTERNAL_DATABASE_NAME)
            } else {
                putString(KEY_EXTERNAL_DATABASE_NAME, name)
            }
        }
    }

    fun shouldKeepExternalMode(context: Context): Boolean {
        return context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .getBoolean(KEY_KEEP_EXTERNAL_MODE, false)
    }

    fun setKeepExternalMode(context: Context, keep: Boolean) {
        context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit { putBoolean(KEY_KEEP_EXTERNAL_MODE, keep) }
    }
}
